import dynamic from 'next/dynamic';
import { getPricingConfig, type PricingConfig } from '@/lib/pricing';

// Carga dinámica para evitar errores de GSAP/Window en el build de servidor
const PremiumLanding = dynamic(
  () => import('@/components/landing/new-landing/PremiumLanding'),
  { ssr: false }
);

const BASE_URL = process.env.NEXT_PUBLIC_APP_URL || 'https://lookitry.com';

export const metadata = {
  title: 'Lookitry — Probador Virtual con IA para tu Tienda de Ropa',
  description: 'Activa el probador virtual con inteligencia artificial en tu tienda en 10 minutos. Sin apps, sin desarrollo. Para marcas que venden por Instagram o WhatsApp.',
  alternates: { canonical: BASE_URL },
  openGraph: {
    title: 'Lookitry — Probador Virtual con IA',
    description: 'Tu tienda online profesional con probador virtual IA integrado, sin pagar un diseñador ni saber de código.',
    url: BASE_URL,
    siteName: 'Lookitry',
    locale: 'es_CO',
    type: 'website',
  },
};

export default async function HomePage() {
  let pricing;
  try {
    pricing = await getPricingConfig();
  } catch {
    pricing = null;
  }

  const basicPrice = pricing?.basic?.precio_mensual_cop ?? 180000;
  const proPrice = pricing?.pro?.precio_mensual_cop ?? 350000;

  const API_URL = process.env.NEXT_PUBLIC_API_URL || 'https://api.lookitry.com';

  let dynamicReviews: any[] = [];
  try {
    const res = await fetch(`${API_URL}/api/reviews/public`, { 
        next: { revalidate: 3600 } 
    });
    if (res.ok) {
        const data = await res.json();
        if (data.reviews && data.reviews.length > 0) {
            dynamicReviews = data.reviews;
        }
    }
  } catch (err) {
    console.error("Error fetching reviews", err);
  }

  // Testimonios curados para la home premium como fallback si falla la bd o hay pocas
  const mockReviews = [
    {
      id: 'mock-1',
      rating: 5,
      comment: "Lookitry no solo nos dio una web, nos dio una herramienta de ventas real. La tasa de retorno de clientes que usan el probador es increíble.",
      reviewer_name: "Elena Martínez",
      reviewer_plan: "PRO",
      is_featured: true,
      created_at: new Date().toISOString(),
      avatar_url: null
    },
    {
      id: 'mock-2',
      rating: 5,
      comment: "Increíble cómo cambió la percepción de mi marca. Mis clientas de WhatsApp ahora entran al link, prueban y compran. ¡Ahorro horas!",
      reviewer_name: "Sofía Rodríguez",
      reviewer_plan: "BASIC",
      is_featured: true,
      created_at: new Date().toISOString(),
      avatar_url: null
    },
    {
      id: 'mock-3',
      rating: 5,
      comment: "El plugin de WooCommerce se instaló en 5 minutos. Mis ventas subieron un 30% en el primer mes de uso.",
      reviewer_name: "Carlos Gómez",
      reviewer_plan: "PRO",
      is_featured: true,
      created_at: new Date().toISOString(),
      avatar_url: null
    }
  ];

  const finalReviews = [...dynamicReviews];
  if (finalReviews.length < 5) {
      finalReviews.push(...mockReviews.slice(0, 5 - finalReviews.length));
  }

  const jsonLd = {
    // ... (rest of jsonLd remains the same)
    '@context': 'https://schema.org',
    '@graph': [
      {
        '@type': 'Organization',
        '@id': `${BASE_URL}/#organization`,
        name: 'Lookitry',
        url: BASE_URL,
        logo: { '@type': 'ImageObject', url: `${BASE_URL}/logo.svg` },
        contactPoint: {
          '@type': 'ContactPoint',
          telephone: '+57-310-543-6281',
          contactType: 'customer service',
          areaServed: ['CO', 'MX', 'AR', 'CL', 'PE', 'VE'],
          availableLanguage: 'Spanish',
        },
      },
      {
        '@type': 'WebSite',
        '@id': `${BASE_URL}/#website`,
        url: BASE_URL,
        name: 'Lookitry',
        publisher: { '@id': `${BASE_URL}/#organization` },
        inLanguage: 'es',
      },
      {
        '@type': 'SoftwareApplication',
        '@id': `${BASE_URL}/#software`,
        name: 'Lookitry',
        applicationCategory: 'BusinessApplication',
        operatingSystem: 'Web',
        url: BASE_URL,
        description: 'Probador virtual con IA para tiendas de ropa, accesorios y calzado en Latinoamerica.',
        offers: [
          {
            '@type': 'Offer',
            name: 'Plan Basico',
            price: String(basicPrice),
            priceCurrency: 'COP',
            priceValidUntil: '2027-12-31',
            availability: 'https://schema.org/InStock',
            url: `${BASE_URL}/planes`,
          },
          {
            '@type': 'Offer',
            name: 'Plan Pro',
            price: String(proPrice),
            priceCurrency: 'COP',
            priceValidUntil: '2027-12-31',
            availability: 'https://schema.org/InStock',
            url: `${BASE_URL}/planes`,
          },
        ],
      },
    ],
  };

  return (
    <>
      <script
        type="application/ld+json"
        dangerouslySetInnerHTML={{ __html: JSON.stringify(jsonLd) }}
      />
      <PremiumLanding 
        pricing={pricing as PricingConfig} 
        reviews={finalReviews} 
        realReviewsCount={dynamicReviews.length}
        usingMockReviews={finalReviews.some(r => r.id.startsWith('mock-'))}
      />
    </>
  );
}

'use client';

import { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Sparkles } from 'lucide-react';

interface GenerationLoaderProps {
  productName: string;
  primaryColor?: string;
  messages?: string[];
  textColor?: string;
  mutedColor?: string;
}

const DEFAULT_MESSAGES = [
  'Analizando tu foto...',
  'Estudiando el producto...',
  'Aplicando el producto...',
  'Ajustando proporciones...',
  'Refinando detalles...',
  'Casi listo...',
];

export function GenerationLoader({ 
  productName, 
  primaryColor = '#FF5C3A', 
  messages = DEFAULT_MESSAGES,
  textColor = '#ffffff',
  mutedColor = '#999999',
}: GenerationLoaderProps) {
  const [msgIndex, setMsgIndex] = useState(0);
  const [progress, setProgress] = useState(0);
  const [prevMsgIndex, setPrevMsgIndex] = useState(0);

  useEffect(() => {
    const msgInterval = setInterval(() => {
      setMsgIndex((i) => (i + 1) % messages.length);
    }, 3500);

    // Smoother progress - starts slow, accelerates in middle, slows at end
    const progressInterval = setInterval(() => {
      setProgress((p) => {
        if (p >= 95) {
          // Slow down near the end
          return Math.min(p + Math.random() * 0.5, 99);
        } else if (p > 60) {
          // Medium speed in middle
          return p + Math.random() * 2;
        } else if (p > 20) {
          // Faster in middle
          return p + Math.random() * 4;
        } else {
          // Slow start
          return p + Math.random() * 1.5;
        }
      });
    }, 800);

    return () => { 
      clearInterval(msgInterval); 
      clearInterval(progressInterval);
    };
  }, [messages.length]);

  // Track message change for animation
  useEffect(() => {
    if (msgIndex !== prevMsgIndex) {
      setPrevMsgIndex(msgIndex);
    }
  }, [msgIndex, prevMsgIndex]);

  return (
    <div className="flex flex-col items-center justify-center py-6 md:py-12 px-4 w-full max-w-sm mx-auto">
      {/* Skeleton shimmer effect */}
      <motion.div 
        className="relative w-20 h-20 md:w-24 md:h-24 mb-5 md:mb-6"
        initial={{ opacity: 0, scale: 0.8 }}
        animate={{ opacity: 1, scale: 1 }}
        transition={{ duration: 0.5, ease: 'easeOut' }}
      >
        {/* Outer ring */}
        <div className="absolute inset-0 rounded-full border-4 opacity-20" style={{ borderColor: mutedColor }} />

        {/* Spinning arc */}
        <motion.div 
          className="absolute inset-0 rounded-full border-4 border-transparent"
          animate={{ rotate: 360 }}
          transition={{ duration: 1.2, repeat: Infinity, ease: 'linear' }}
          style={{ borderTopColor: primaryColor }}
        />

        {/* Inner spinning arc (reverse) */}
        <motion.div 
          className="absolute inset-2 md:inset-3 rounded-full border-4 border-transparent"
          animate={{ rotate: -360 }}
          transition={{ duration: 1.8, repeat: Infinity, ease: 'linear' }}
          style={{ borderTopColor: `${primaryColor}50` }}
        />

        {/* Center icon */}
        <motion.div 
          className="absolute inset-0 flex items-center justify-center"
          animate={{ 
            scale: [1, 1.1, 1],
            opacity: [0.8, 1, 0.8]
          }}
          transition={{ duration: 2, repeat: Infinity, ease: 'easeInOut' }}
        >
          <Sparkles className="w-7 h-7 md:w-9 md:h-9" style={{ color: primaryColor }} strokeWidth={1.5} />
        </motion.div>
      </motion.div>

      {/* Title */}
      <motion.h2 
        className="text-base md:text-lg font-black uppercase italic tracking-tight text-center mb-1"
        style={{ color: textColor }}
        initial={{ opacity: 0, y: 10 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ delay: 0.2 }}
      >
        Generando look
      </motion.h2>

      {/* Product name */}
      <motion.p 
        className="text-[10px] md:text-xs text-center font-bold uppercase tracking-widest mb-5"
        style={{ color: mutedColor }}
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        transition={{ delay: 0.3 }}
      >
        Probando <span style={{ color: textColor }}>{productName}</span>
      </motion.p>

      {/* Progress bar - smooth animation */}
      <motion.div 
        className="w-full max-w-[180px] md:max-w-[220px] h-1.5 rounded-full overflow-hidden mb-4 shadow-inner"
        style={{ backgroundColor: `${mutedColor}30` }}
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        transition={{ delay: 0.4 }}
      >
        <motion.div 
          className="h-full rounded-full"
          style={{ 
            backgroundColor: primaryColor,
            boxShadow: `0 0 10px ${primaryColor}60`
          }}
          animate={{ 
            width: `${Math.min(progress, 100)}%`,
          }}
          transition={{ 
            duration: 0.8, 
            ease: 'easeOut'
          }}
        />
      </motion.div>

      {/* Percentage indicator */}
      <motion.div 
        className="text-[10px] md:text-xs font-medium mb-3"
        style={{ color: mutedColor }}
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        transition={{ delay: 0.5 }}
      >
        {Math.round(progress)}%
      </motion.div>

      {/* Animated message */}
      <div className="h-5 md:h-6 flex items-center justify-center">
        <AnimatePresence mode="wait">
          <motion.p 
            key={msgIndex}
            className="text-[10px] md:text-xs font-medium text-center uppercase tracking-tighter"
            style={{ color: mutedColor }}
            initial={{ opacity: 0, y: 5 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: -5 }}
            transition={{ duration: 0.3 }}
          >
            {messages[msgIndex]}
          </motion.p>
        </AnimatePresence>
      </div>

      {/* Brand indicator */}
      <motion.div 
        className="mt-8 md:mt-10 flex items-center gap-2"
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        transition={{ delay: 0.6 }}
      >
        <motion.div 
          className="w-2 h-2 rounded-full"
          style={{ backgroundColor: primaryColor }}
          animate={{ 
            opacity: [1, 0.5, 1],
            scale: [1, 1.2, 1]
          }}
          transition={{ duration: 1.5, repeat: Infinity }}
        />
        <p className="text-[9px] md:text-[10px] font-black uppercase tracking-[0.2em]" style={{ color: mutedColor }}>
          IA LOOKITRY ACTIVE
        </p>
      </motion.div>
    </div>
  );
}

'use client';

import React from 'react';
import { Star } from 'lucide-react';
import Image from 'next/image';
import { PublicReview } from '@/types';

interface LandingReviewsProps {
  reviews: PublicReview[];
}

const SectionTag = ({ text, light = false }: { text: string; light?: boolean }) => (
  <div className={`inline-flex items-center gap-2 px-3 sm:px-4 py-1.5 sm:py-2 rounded-full mb-6 sm:mb-8 font-medium text-[9px] sm:text-[10px] uppercase tracking-[0.15em] sm:tracking-[0.2em] border shadow-sm transition-all ${light
      ? 'bg-black/5 border-black/10 text-black/40 dark:bg-white/5 dark:border-white/10 dark:text-white/60'
      : 'bg-[#FF5C3A]/5 border-[#FF5C3A]/20 text-[#FF5C3A]'
    }`}>
    <span className={`w-1.5 h-1.5 rounded-full animate-pulse ${light ? 'bg-black/20 dark:bg-white/40' : 'bg-[#FF5C3A]'}`} aria-hidden="true" />
    {text}
  </div>
);

export default function LandingReviews({ reviews }: LandingReviewsProps) {
  if (!reviews || reviews.length === 0) return null;

  return (
    <section className="bg-white dark:bg-black py-20 sm:py-24 md:py-28 lg:py-32 px-4 sm:px-6 border-y border-[#eeebe7] dark:border-white/5 relative overflow-hidden" aria-label="Testimonios de clientes">
      <div className="absolute inset-0 z-0 opacity-30 pointer-events-none" aria-hidden="true">
        <div className="absolute top-1/2 left-0 w-72 sm:w-96 h-72 sm:h-96 bg-[#FF5C3A]/5 blur-[120px] rounded-full" />
      </div>

      <div className="max-w-7xl mx-auto relative z-10">
        <div className="text-center mb-12 sm:mb-16 md:mb-20">
          <SectionTag text="Casos de Éxito" light />
          <h2 className="font-jakarta text-3xl sm:text-4xl md:text-5xl font-bold text-black dark:text-white mb-4 sm:mb-6">Marcas que ya <span className="text-[#FF5C3A]">brillan con IA.</span></h2>
          <p className="font-dm-sans text-[#666] dark:text-white/50 text-base sm:text-lg max-w-2xl mx-auto font-light">
            Únete a la revolución del retail digital con tecnología de vanguardia.
          </p>
        </div>

        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6 sm:gap-8">
          {reviews.slice(0, 6).map((rev, i) => (
            <div key={i} className="bg-[#f8f6f4] dark:bg-[#111] border border-[#e8e4df] dark:border-white/5 p-6 sm:p-8 rounded-2xl sm:rounded-[2.5rem] hover:border-[#FF5C3A]/40 transition-all duration-500 group relative overflow-hidden">
              <div className="absolute top-0 right-0 p-6 sm:p-8 opacity-[0.03] dark:opacity-[0.07] group-hover:opacity-[0.07] transition-opacity" aria-hidden="true">
                <Star size={80} fill="currentColor" className="text-black dark:text-white" />
              </div>

              <div className="flex items-center gap-1 mb-4 sm:mb-6 text-[#FF5C3A]" aria-label={`${rev.rating} de 5 estrellas`}>
                {Array.from({ length: 5 }).map((_, s) => (
                  <Star 
                    key={s} 
                    size={14} 
                    fill={s < rev.rating ? "#FF5C3A" : "none"} 
                    className={s < rev.rating ? "text-[#FF5C3A]" : "text-[#e8e4df] dark:text-white/10"}
                    aria-hidden="true"
                  />
                ))}
              </div>

              <p className="text-[#333] dark:text-white/80 font-dm-sans leading-relaxed mb-6 sm:mb-8 italic relative z-10 text-sm sm:text-[15px] font-light">
                &quot;{rev.comment}&quot;
              </p>

              <div className="flex items-center gap-3 sm:gap-4 border-t border-[#e8e4df] dark:border-white/5 pt-4 sm:pt-6 relative z-10">
                {rev.avatar_url ? (
                  <Image 
                    src={rev.avatar_url} 
                    alt={rev.reviewer_name} 
                    width={48} 
                    height={48}
                    className="w-10 h-10 sm:w-12 sm:h-12 rounded-xl sm:rounded-2xl object-cover shadow-lg shadow-[#FF5C3A]/10 transition-transform group-hover:scale-110 shrink-0"
                    unoptimized={rev.avatar_url.toLowerCase().endsWith('.svg')}
                  />
                ) : (
                  <div className="w-10 h-10 sm:w-12 sm:h-12 rounded-xl sm:rounded-2xl bg-[#FF5C3A] flex items-center justify-center font-jakarta font-bold text-base sm:text-lg text-white shadow-lg shadow-[#FF5C3A]/20 transition-transform group-hover:scale-110 shrink-0">
                    {rev.reviewer_name.charAt(0)}
                  </div>
                )}
                <div>
                  <h4 className="font-jakarta font-bold text-xs sm:text-sm text-black dark:text-white group-hover:text-[#FF5C3A] transition-colors">{rev.reviewer_name}</h4>
                  <p className="text-[9px] sm:text-[10px] text-[#666] dark:text-white/40 uppercase tracking-[0.15em] sm:tracking-[0.2em] font-bold">{rev.reviewer_plan}</p>
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}

'use client';

import { useEffect, useMemo, useRef, useState } from 'react';
import Image from 'next/image';
import { ChevronLeft, ChevronRight, Star } from 'lucide-react';
import type { PublicReview } from '@/types';

interface ReviewsSliderProps {
  reviews: PublicReview[];
  realReviewsCount: number;
  usingMockReviews: boolean;
}

function formatDate(date: string): string {
  return new Date(date).toLocaleDateString('es-CO', { month: 'long', year: 'numeric' });
}

function getInitials(name: string): string {
  return name
    .split(' ')
    .map((part) => part.trim().charAt(0))
    .filter(Boolean)
    .slice(0, 2)
    .join('')
    .toUpperCase();
}

export function ReviewsSlider({ reviews, realReviewsCount, usingMockReviews }: ReviewsSliderProps) {
  const [activeIndex, setActiveIndex] = useState(0);
  const [paused, setPaused] = useState(false);
  const intervalRef = useRef<number | null>(null);
  const slides = useMemo(() => reviews, [reviews]);

  useEffect(() => {
    if (slides.length <= 1 || paused) return;

    intervalRef.current = window.setInterval(() => {
      setActiveIndex((current) => (current + 1) % slides.length);
    }, 4000);

    return () => {
      if (intervalRef.current) window.clearInterval(intervalRef.current);
    };
  }, [slides.length, paused]);

  if (!slides.length) return null;

  const goTo = (index: number) => {
    if (index < 0) {
      setActiveIndex(slides.length - 1);
      return;
    }
    setActiveIndex(index % slides.length);
  };

  return (
    <section className="bg-white dark:bg-[#0d0d0d] px-4 sm:px-6 md:px-8 py-12 sm:py-16 md:py-20" aria-label="Reviews de clientes">
      <div className="mx-auto max-w-5xl sm:max-w-[1180px]">
        <div className="mb-8 sm:mb-10 text-center">
          <p className="mb-2 sm:mb-3 text-[10px] sm:text-[11px] font-medium uppercase tracking-[0.12em] text-[#FF5C3A]">Reviews</p>
          <h2 className="text-2xl sm:text-3xl font-bold tracking-tight text-[#0a0a0a] dark:text-white md:text-4xl">Lo que dicen nuestras marcas</h2>
          <p className="mx-auto mt-2 sm:mt-3 max-w-2xl text-sm leading-relaxed text-[#666] dark:text-white/60 md:text-base">
            Opiniones reales de marcas que ya usan Lookitry
          </p>
        </div>

        <div className="relative" onMouseEnter={() => setPaused(true)} onMouseLeave={() => setPaused(false)}>
          <button
            type="button"
            onClick={() => goTo(activeIndex - 1)}
            className="absolute left-0 sm:-left-2 top-1/2 z-10 hidden -translate-x-1/2 -translate-y-1/2 rounded-full border border-[#d7d0c7] dark:border-white/10 bg-white/95 dark:bg-[#1a1a1a] p-2.5 sm:p-3 text-[#0a0a0a] dark:text-white shadow-lg transition-all hover:scale-105 md:flex"
            aria-label="Ver review anterior"
          >
            <ChevronLeft className="h-4 w-4 sm:h-5 sm:w-5" aria-hidden="true" />
          </button>

          <div className="overflow-hidden">
            <div className="flex transition-transform duration-500 ease-out" style={{ transform: `translateX(-${activeIndex * 100}%)` }}>
              {slides.map((_, slideIndex) => (
                <div key={`slide-${slides[slideIndex].id}`} className="min-w-full">
                  <div className="grid grid-cols-1 gap-4 sm:gap-5 md:grid-cols-3">
                    {[0, 1, 2].map((offset) => {
                      const review = slides[(slideIndex + offset) % slides.length];
                      return (
                        <article
                          key={`${review.id}-${offset}`}
                          className={`${offset > 0 ? 'hidden md:flex' : 'flex'} h-full flex-col rounded-2xl sm:rounded-[28px] border border-[#e0dcd7] dark:border-white/5 bg-white dark:bg-[#141414] p-5 sm:p-6 shadow-[0_20px_60px_rgba(15,15,15,0.06)] dark:shadow-none`}
                        >
                          <div className="mb-4 sm:mb-5 flex items-center justify-between gap-4">
                            <div className="flex items-center gap-0.5 sm:gap-1" aria-label={`${review.rating} de 5 estrellas`}>
                              {Array.from({ length: 5 }).map((__, starIndex) => {
                                const filled = review.rating >= starIndex + 1;
                                const halfFilled = !filled && review.rating >= starIndex + 0.5;

                                return (
                                  <div key={`${review.id}-${starIndex}`} className="relative h-3.5 w-3.5 sm:h-4 sm:w-4 shrink-0">
                                    <Star className="absolute inset-0 text-[#e7dfd6] dark:text-white/10" aria-hidden="true" />
                                    {filled && (
                                      <Star className="absolute inset-0 fill-[#FF5C3A] text-[#FF5C3A]" aria-hidden="true" />
                                    )}
                                    {!filled && halfFilled && (
                                      <div className="absolute inset-y-0 left-0 overflow-hidden w-1/2">
                                        <Star className="h-3.5 w-3.5 sm:h-4 sm:w-4 fill-[#FF5C3A] text-[#FF5C3A] max-w-none" aria-hidden="true" />
                                      </div>
                                    )}
                                  </div>
                                );
                              })}
                            </div>
                            <span className="rounded-full border border-[#f1d5cd] dark:border-[#FF5C3A]/20 bg-[#fff4f1] dark:bg-[#FF5C3A]/10 px-2 sm:px-2.5 py-0.5 sm:py-1 text-[9px] sm:text-[10px] font-bold uppercase tracking-[0.16em] text-[#FF5C3A]">
                              {review.reviewer_plan}
                            </span>
                          </div>

                          <p className="flex-1 text-sm sm:text-[15px] leading-6 sm:leading-7 text-[#3f3a35] dark:text-white/80">&ldquo;{review.comment}&rdquo;</p>

                          <div className="mt-4 sm:mt-6 flex items-center gap-2.5 sm:gap-3 border-t border-[#f0ebe5] dark:border-white/5 pt-4 sm:pt-5">
                            {review.avatar_url ? (
                              <Image 
                                src={review.avatar_url} 
                                alt={review.reviewer_name} 
                                width={40} 
                                height={40} 
                                className="h-9 w-9 sm:h-10 sm:w-10 rounded-full object-cover shrink-0" 
                                unoptimized={review.avatar_url.toLowerCase().endsWith('.svg')}
                              />
                            ) : (
                              <div className="flex h-9 w-9 sm:h-10 sm:w-10 items-center justify-center rounded-full bg-[#FF5C3A] text-xs sm:text-sm font-bold text-white shrink-0">
                                {getInitials(review.reviewer_name)}
                              </div>
                            )}
                            <div>
                              <p className="font-semibold text-sm text-[#0a0a0a] dark:text-white">{review.reviewer_name}</p>
                              <p className="text-[10px] sm:text-xs uppercase tracking-[0.12em] sm:tracking-[0.16em] text-[#8a8178] dark:text-white/40">{formatDate(review.created_at)}</p>
                            </div>
                          </div>
                        </article>
                      );
                    })}
                  </div>
                </div>
              ))}
            </div>
          </div>

          <button
            type="button"
            onClick={() => goTo(activeIndex + 1)}
            className="absolute right-0 sm:-right-2 top-1/2 z-10 hidden translate-x-1/2 -translate-y-1/2 rounded-full border border-[#d7d0c7] dark:border-white/10 bg-white/95 dark:bg-[#1a1a1a] p-2.5 sm:p-3 text-[#0a0a0a] dark:text-white shadow-lg transition-all hover:scale-105 md:flex"
            aria-label="Ver siguiente review"
          >
            <ChevronRight className="h-4 w-4 sm:h-5 sm:w-5" aria-hidden="true" />
          </button>
        </div>

        <div className="mt-6 sm:mt-8 flex items-center justify-center gap-1.5 sm:gap-2">
          {slides.map((review, index) => (
            <button
              key={`dot-${review.id}`}
              type="button"
              onClick={() => goTo(index)}
              className={`h-2 sm:h-2.5 rounded-full transition-all ${index === activeIndex ? 'w-6 sm:w-8 bg-[#FF5C3A]' : 'w-2 sm:w-2.5 bg-[#d1c8be] dark:bg-white/20'}`}
              aria-label={`Ir a la review ${index + 1}`}
            />
          ))}
        </div>

        {process.env.NODE_ENV === 'development' && usingMockReviews && (
          <p className="mt-4 text-center text-xs text-yellow-600 dark:text-yellow-400">
            [DEV] Mostrando mock reviews — faltan {Math.max(0, 5 - realReviewsCount)} reviews reales aprobadas
          </p>
        )}
      </div>
    </section>
  );
}

